$f = Formula("-1/4(x + 2)(x - 6)");
Context("Point");
$vertex = Point("(2, 4)");
$roots = List("-2,6");
$iv = $f->eval(x => 0);
$is = $f->D()->eval(x => 0);
$curv = DropDown(['positive', 'negative'], 1, showInStatic => 0);

$image_1 = createLaTeXImage();
$image_1->addToPreamble(latexImagePreamble());
$image_1->BEGIN_LATEX_IMAGE
\begin{tikzpicture}
  \begin{axis}
    \addplot[domain=-4.5:7] {-1/4*(x+2)*(x-6)};
  \end{axis}
\end{tikzpicture}

END_LATEX_IMAGE

